import { useState } from "react";

import {
  Container,
  Typography,
  Box,
  AppBar,
  Toolbar,
  Button,
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableRow,
  Paper,
  Pagination,
} from "@mui/material";

import "./BoardPage.css";

function BoardPage() {
  const posts = [];

  const [page, setPage] = useState(1);
  const pageSize = 9;

  const handleChange = (event, value) => {
    setPage(value);
  };

  const startIndex = (page - 1) * pageSize;

  const currentPosts = posts.slice(
    startIndex,
    startIndex + pageSize
  );

  return (
    <>
      {/* Navbar */}
      <AppBar position="static" className="navbar">
        <Toolbar className="navbar-toolbar">

          {/* 로고 */}
          <img
            src="/kw_logo.png"
            className="navbar-logo"
            alt="logo"
          />

          {/* 오른쪽 버튼 */}
          <Box sx={{ marginLeft: "auto" }}>

            {/* 검색 버튼 */}
            <Button className="nav-button">
              검색
            </Button>

            {/* 게시물 등록 */}
            <Button className="nav-button">
              게시물 등록
            </Button>

            {/* 로그아웃 */}
            <Button className="nav-button logout-btn">
              로그아웃
            </Button>

          </Box>

        </Toolbar>
      </AppBar>

      {/* 배너 */}
      <Box className="board-header">

        <Typography
          variant="h4"
          className="board-title"
        >
          게시판
        </Typography>

        <Typography className="board-subtitle">
          등록된 게시글이 없습니다
        </Typography>

      </Box>

      {/* 게시판 */}
      <Container className="board-container">

        <Paper className="board-table-wrapper">

          <Table>

            <TableHead>
              <TableRow className="table-head">
                <TableCell>ID</TableCell>
                <TableCell>제목</TableCell>
                <TableCell>내용</TableCell>
              </TableRow>
            </TableHead>

            <TableBody>
              {currentPosts.length === 0 ? (
                <TableRow>
                  <TableCell
                    colSpan={3}
                    align="center"
                  >
                    게시글이 없습니다.
                  </TableCell>
                </TableRow>
              ) : (
                currentPosts.map((post) => (
                  <TableRow
                    key={post.id}
                    className="table-row"
                  >
                    <TableCell>{post.id}</TableCell>
                    <TableCell>{post.title}</TableCell>
                    <TableCell>{post.content}</TableCell>
                  </TableRow>
                ))
              )}
            </TableBody>

          </Table>

        </Paper>

        {/* 페이지네이션 */}
        <Box
          sx={{
            display: "flex",
            justifyContent: "center",
            mt: 3,
          }}
        >
          <Pagination
            count={Math.ceil(posts.length / pageSize) || 1}
            page={page}
            onChange={handleChange}
            color="primary"
          />
        </Box>

      </Container>
    </>
  );
}

export default BoardPage;
